const safeMode = global.get('safe_mode') || false;
const throttleMode = global.get('throttle_mode') || false;

// 获取 checkpoint_ms (从 context 获取，SQLite Init 会在启动时写入参考值)
const checkpointMs = env.get('CHECKPOINT_MS') || 0;

msg.payload = {
    status: 'healthy',
    version: env.get('RUNTIME_VERSION') || 'v3.4',
    safe_mode: safeMode,
    throttle_mode: throttleMode,
    checkpoint_ms: parseInt(checkpointMs),
    uptime: process.uptime(),
    timestamp: new Date().toISOString()
};

// 如果安全模式，返回 503
if (safeMode) {
    msg.statusCode = 503;
    msg.payload.status = 'safe_mode';
}

return msg;

const tid = msg.trace_id || msg._msgid || ('m' + Date.now());
msg.trace_id = tid;

const p = Array.isArray(msg.payload)
    ? (msg.payload[0] != null ? msg.payload[0] : {})
    : (msg.payload != null ? msg.payload : {});

// 入库拒收校验 (010-nodered-core.mdc 第4条)
if (!p.order_id || p.weight == null || p.weight <= 0 || !p.location) {
    msg.statusCode = 400;
    msg.payload = {
        error: 'INVALID',
        tid: tid,
        details: 'order_id/weight(>0)/location required'
    };
    return msg;
}

// 安全模式检查
const safeMode = global.get('safe_mode');
if (safeMode) {
    msg.statusCode = 503;
    msg.payload = {
        error: 'SAFE_MODE',
        tid: tid,
        details: 'System in safe mode, order rejected'
    };
    return msg;
}

msg._validated = {
    order_id: p.order_id,
    weight: p.weight,
    location: p.location,
    brand: p.brand || 'generic',
    zone_id: p.zone_id || null,
    priority: p.priority || 0
};

return msg;

const v = msg._validated;

// 分配 zone_token (区域锁)
const zoneToken = v.zone_id ? ('zt_' + Date.now() + '_' + Math.random().toString(36).substr(2, 8)) : null;

msg.payload = {
    order_no: v.order_id,
    status: 'CREATED',
    weight: v.weight,
    location: v.location,
    zone_id: v.zone_id,
    zone_token: zoneToken,
    brand: v.brand,
    priority: v.priority,
    created_at: new Date().toISOString(),
    version: 1
};

return msg;

// Outbox 写入: audit_log + orders (010-nodered-core.mdc 第3条)
const order = msg.payload;

// 写入 audit_log
msg.audit_event = {
    event: 'ORDER_CREATED',
    order_no: order.order_no,
    status: 'CREATED',
    timestamp: new Date().toISOString(),
    trace_id: msg.trace_id
};

return msg;

const order = msg.payload;

// 品牌路由策略 (v3.4 策略模式)
const brand = order.brand || 'generic';

// 电量检查 (模拟，生产环境从 robot_status 表读取)
// 电量 < 20% 限制短单

msg.next_status = 'DISPATCHED';
msg.current_status = 'CREATED';

// 状态机校验 (050-state-machine.mdc)
const ok = {
    CREATED: ['DISPATCHED','CANCELLED'],
    DISPATCHED: ['EXECUTING','SUSPENDED','RECALLING','CANCELLED'],
    EXECUTING: ['COMPLETED','DIFF_SUSPENDED','SUSPENDED'],
    COMPLETED: ['SAP_CONFIRMED','SAP_PENDING'],
    SUSPENDED: ['DISPATCHED','MANUAL_HANDLED','CANCELLED','DEGRADED'],
    DIFF_SUSPENDED: ['COMPLETED','MANUAL_HANDLED','SUSPENDED'],
    RECALLING: ['CANCELLED'],
    SAP_PENDING: ['SAP_CONFIRMED','SUSPENDED']
};

const A = msg.current_status;
const B = msg.next_status;

if (A && B && ok[A] && ok[A].indexOf(B) === -1) {
    msg.statusCode = 409;
    msg.payload = { error: 'BAD_STATE', A: A, B: B, tid: msg.trace_id };
    return msg;
}

msg.payload.status = 'DISPATCHED';
msg.payload.updated_at = new Date().toISOString();

return msg;

// 由 Watchdog 或主管手动触发
global.set('safe_mode', true);

msg.payload = {
    status: 'SAFE_MODE_ENTERED',
    timestamp: new Date().toISOString()
};

return msg;

global.set('safe_mode', false);

msg.payload = {
    status: 'SAFE_MODE_EXITED',
    timestamp: new Date().toISOString()
};

return msg;

// 从 Redis 读取系统安全模式标志
// Watchdog 写入 system:safe_mode 时自动进入安全模式
// 生产环境: 使用 contextStorage.redis 读取

// 模拟: 检查 context (Redis context 启用后自动同步)
const redisSafeMode = env.get('REDIS_SAFE_MODE');

if (redisSafeMode) {
    global.set('safe_mode', true);
    node.warn('[WATCHDOG] 安全模式已由 Watchdog 激活: ' + redisSafeMode);
} else {
    // 不自动解除，需人工 /api/restore-mode
}

return msg;

// 返回当前区域锁状态
// 生产环境从 SQLite zone_lock 表读取

msg.payload = {
    zones: global.get('zone_locks') || {},
    timestamp: new Date().toISOString()
};

return msg;
